      <div v-show="activeSection === 'config'" v-if="currentChangeRuleData.length">
        <div class="card-body float-left w-100" >
          <!-- Current Version -->
          <div class="w-48 float-left" >
            <div class="col-lg-12 mb-2 p-0">                                
                   <div class="heading-border">
                        <h5 class="h5">
