              <div class="col-lg-12 mb-2">
                  <div class="p-2 bg-grey text-center"><b class="font-weight-medium">{{ $t('ClientName') }}:</b> {{ item.BillingRuleClientName }}</div>
              </div>
              <div class="col-lg-12 mb-2">
                  <div class="p-2 bg-grey text-center"><b class="font-weight-medium">{{ $t('CreatedBy') }}:</b> {{ item.BillingRuleCreatedBy }}</div>
              </div>
              <div class="col-lg-12 mb-2">
                  <div class="p-2 bg-grey text-center"><b class="font-weight-medium">{{ $t('CreatedDate') }}:</b> {{ formatDate(item.BillingRuleCreatedAt) }}</div>
              </div>
              <div class="col-lg-12 mb-2">
                  <div class="p-2 bg-grey text-center"><b class="font-weight-medium">{{ $t('ModifiedBy') }}:</b> {{ item.BillingRuleModifyBy }}</div>
              </div>
              <div class="col-lg-12 mb-2">
                  <div class="p-2 bg-grey text-center"><b class="font-weight-medium">{{ $t('ModifiedDate') }}:</b> {{ formatDate(item.BillingRuleModifyAt) }}</div>
              </div>
              <div class="col-lg-12 mb-2">
                  <div class="p-2 bg-grey text-center"><b class="font-weight-medium">{{ $t('EffectiveFrom') }}:</b> {{ formatDate(item.EfficativeDateFrom) }}</div>
              </div>
              <div class="col-lg-12 mb-2">
                  <div class="p-2 bg-grey text-center"><b class="font-weight-medium">{{ $t('EffectiveTo') }}:</b> {{ formatDate(item.EfficativeDateTo) }}</div>
              </div>
              <div class="col-lg-12 mb-2">
                  <div class="p-2 bg-grey text-center"><b class="font-weight-medium">{{ $t('ChargeType') }}:</b> {{ item.ChargeType || '--' }}</div>
              </div>
              <div class="col-lg-12 mb-2">
                  <div class="p-2 bg-grey text-center"><b class="font-weight-medium">{{ $t('IsRuleApllicableToAllName') }}:</b> {{ item.IsRuleApplicableToAll ? 'Yes' : 'No' }}</div>
              </div>
              <div class="col-lg-12 mb-2">
                  <div class="p-2 bg-grey text-center"><b class="font-weight-medium">{{ $t('UtilityName') }}:</b> {{ item.UtilityName }}</div>
              </div>
              <div class="col-lg-12 mb-2">
