              </div>
            </div>
          </div>

          <!-- Previous Version -->
          <div class="w-48 float-right" v-if="previousChangeRuleData && previousChangeRuleData.some(item => item.RuleVersion !== null)">
              <div class="col-lg-12 mb-2 p-0">                                
                <div class="heading-border">
                    <h5 class="h5">
                      <span v-if="previousLabel">{{ previousLabel }}</span>
                      <span v-else class="text-muted">Version Number :</span>
