                </div>                              
              </div>

              <div class="history-item" v-for="item in previousChangeRuleData" :key="item.ConfigurationId">

                <div class="col-lg-12 mb-2">
                    <div class="p-2 bg-grey text-center"><b class="font-weight-medium">{{ $t('BillingRuleName') }}:</b> {{ item.BillingConfigName }}</div>
                </div>
                <div class="col-lg-12 mb-2">
                    <div class="p-2 bg-grey text-center"><b class="font-weight-medium">{{ $t('ClientName') }}:</b> {{ item.BillingRuleClientName }}</div>
                </div>
                <div class="col-lg-12 mb-2">
                    <div class="p-2 bg-grey text-center"><b class="font-weight-medium">{{ $t('CreatedBy') }}:</b> {{ item.BillingRuleCreatedBy }}</div>
                </div>
                <div class="col-lg-12 mb-2">
                    <div class="p-2 bg-grey text-center"><b class="font-weight-medium">{{ $t('CreatedDate') }}:</b> {{ formatDate(item.BillingRuleCreatedAt) }}</div>
                </div>
                <div class="col-lg-12 mb-2">
                    <div class="p-2 bg-grey text-center"><b class="font-weight-medium">{{ $t('ModifiedBy') }}:</b> {{ item.BillingRuleModifyBy }}</div>
                </div>
                <div class="col-lg-12 mb-2">
                    <div class="p-2 bg-grey text-center"><b class="font-weight-medium">{{ $t('ModifiedDate') }}:</b> {{ formatDate(item.BillingRuleModifyAt) }}</div>
                </div>
                <div class="col-lg-12 mb-2">
                    <div class="p-2 bg-grey text-center"><b class="font-weight-medium">{{ $t('EffectiveFrom') }}:</b> {{ formatDate(item.EfficativeDateFrom) }}</div>
                </div>
                <div class="col-lg-12 mb-2">
                    <div class="p-2 bg-grey text-center"><b class="font-weight-medium">{{ $t('EffectiveTo') }}:</b> {{ formatDate(item.EfficativeDateTo) }}</div>
                </div>
                <div class="col-lg-12 mb-2">
                    <div class="p-2 bg-grey text-center"><b class="font-weight-medium">{{ $t('ChargeType') }}:</b> {{ item.ChargeType || '--' }}</div>
                </div>
                <div class="col-lg-12 mb-2">
                    <div class="p-2 bg-grey text-center"><b class="font-weight-medium">{{ $t('IsRuleApllicableToAllName') }}:</b> {{ item.IsRuleApplicableToAll ? 'Yes' : 'No' }}</div>
                </div>
                <div class="col-lg-12 mb-2">
                    <div class="p-2 bg-grey text-center"><b class="font-weight-medium">{{ $t('UtilityName') }}:</b> {{ item.UtilityName }}</div>
                </div>
                <div class="col-lg-12 mb-2">
                    <div class="p-2 bg-grey text-center"><b class="font-weight-medium">{{ $t('GroupByColumns') }}:</b> {{ item.BillingRuleGroupByName || '--' }}</div>
                </div>
            </div>
          </div>
         
        </div>
      </div>
    </div>

    <!-- Node Comparison Section -->
    <div class="node-section card">
      <div :class="{ 'card-header': true, active: activeSection === 'node' }" @click="toggleSection('node')" :aria-expanded="(activeSection === 'node').toString()"
          tabindex="0"  @keydown.enter="toggleSection('node')" @keydown.space.prevent="toggleSection('node')" role="button">
          <em class="fa fa-angle-down rotate-icon" :class="{ rotated: activeSection === 'node' }" aria-hidden="true"></em>
           {{ $t('BillingRuleChanges') }}
        </div>
      <div class="card-body float-left w-100" v-show="activeSection === 'node'">
        <div class="row">
            <div class="col-12 mb-2">
                  <div class="mr-2 d-inline-block">
                      <span class="legend-pending colorboxsquare"></span> {{ $t('ServiceChangesinRule') }}
                  </div>
                  <div class="mr-2 d-inline-block">
                      <span class="legend-Progress colorboxsquare"></span> {{ $t('NewRule') }}
                  </div>
                  <div class="mr-2 d-inline-block">
                      <span class="legend-ovrdue colorboxsquare"></span> {{ $t('DeletedRule') }}
                  </div>
            </div>
        </div>

        <div class="w-48 float-left" v-if="nodeHistoryFullData && nodeHistoryFullData.length">
            <div class="col-lg-12 mb-2 p-0">                                
                <div class="heading-border">
                    <h5 class="h5"><span>{{ currentLabel }}</span></h5>
                </div>                              
            </div>
          <RecursiveNodeConfigurationHistory  :configurationId="NEW_RULE_ID" :rules="rules" :name="'RecursiveNodeConfiguration'"
                :isBillingType="isBillingType" :clientId="clientId"  :setupId="setupId"></RecursiveNodeConfigurationHistory>
        </div>
        <div class="w-48 float-right">
            <div v-if="nodeHistoryData && nodeHistoryData.length && previousLabel">
              <div class="col-lg-12 mb-2 p-0">
                <div class="heading-border">
                  <h5 class="h5"><span>{{ previousLabel }}</span>
                  </h5>
                </div>
              </div>
              <RecursiveNodeConfigurationHistory :configurationId="OLD_RULE_ID" :rules="rules" :name="'RecursiveNodeConfiguration'" 
                :isBillingType="isBillingType" :clientId="clientId" :setupId="setupId"/>
            </div>
        </div>
      </div>
    </div>
    <div class="card">
        <div :class="{ 'card-header': true, active: activeSection === 'chart' }"
            @click="toggleSection('chart')" :aria-expanded="(activeSection === 'chart').toString()" tabindex="0" @keydown.enter="toggleSection('chart')"
            @keydown.space.prevent="toggleSection('chart')" role="button">
            <em class="fa fa-angle-down rotate-icon":class="{ rotated: activeSection === 'chart' }" aria-hidden="true"></em>
              {{ $t('BillingFlowChart') }}
        </div>

        <div v-show="activeSection === 'chart'" class="card-body">
          <div class="row">
            <div class="col-6">
                <div class="w-100 float-left">
                    <div class="col-lg-12 mb-2 p-0">
                        <div class="heading-border">
                          <h5 class="h5">
                            <span id="divCurrentversionNameFlowChart" class="cont_49" style="display: inline-block;">{{ $t('VersionNumber') }}: {{ currentVersion }}</span>
                          </h5>
                        </div>
                        <div class="col-lg-12 mb-2 p-0 borderbababa cont_49" style="overflow: auto; min-height: 494px; max-height: 494px; overflow-y: auto; max-width: 1168px; overflow-y: auto">
                          <BillingChartHistory :CONFIGURATION_ID="CONFIGURATION_ID" :isChartHistory="isChartHistory" :isBillingType="isBillingType" :clientId="clientId"/>
                        </div>
                    </div>
                </div>
            </div>
            <div class="col-6">
              <div class="w-100 float-left">
                <div v-if="previousVersion && previousVersion > 0">
                  <div class="col-lg-12 mb-2 p-0">
                    <div class="heading-border">
                      <h5 class="h5">
                        <span id="divCurrentversionNameFlowChart"  class="cont_49" style="display: inline-block;">
                          {{ $t('VersionNumber') }}: {{ previousVersion }}
                        </span>
                      </h5>
                    </div>
                  </div>
                  <div class="col-lg-12 mb-2 p-0 borderbababa cont_49" style="overflow: auto; min-height: 494px; max-height: 494px; max-width: 1168px;">
                    <BillingChartHistory :CONFIGURATION_ID="OLD_RULE_ID" :isChartHistory="isChartHistory" :showHistory="1" :isBillingType="isBillingType" :clientId="clientId"/>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>
    </div>
    <!-- <div>
        <RuleServiceUpdate 
          v-if="isRuleServiceUpdateFormVisible" 
          :configurationId="selectedConfigurationId"
          :billingServiceId="BILLING_SERVICE_ID"
          :conditionId ="conditionId"
          :nodeName="nodeName"
          reqFrom="ViewBillingConditionForService"
          closeModalType="isRuleServiceUpdateFormVisible"
        />
    </div> -->

  </div>
</template>

<script>
import BillingChartHistory from '../../../views/BillingRule/BillingRuleHistory/BillingChartHistory.vue';
 import RuleServiceUpdate from '../../../views/BillingRule/BillingRuleHistory/RuleServiceUpdate.vue';
 import RecursiveNodeConfigurationHistory from "../BillingRuleHistory/RecursiveNodeConfigurationHistory.vue";

export default {
  name: 'FlowChartWrapper',
  components: { BillingChartHistory,RuleServiceUpdate,RecursiveNodeConfigurationHistory },
  props: {
    currentChangeRuleData: Array,
    previousChangeRuleData: Array,
    currentVersion: Number,
    previousVersion: Number,
    NEW_RULE_ID: Number,
    OLD_RULE_ID: Number,
    currentConfigurationId: Number,
    addRootNode: Boolean,
    includeGlobalService: Boolean,
    includeDeletedService: Boolean,
    CONFIGURATION_ID: Number,
    nodeHistoryData: Array,
    nodeHistoryFullData: Array,
    serviceId:Array,
    BILLING_SERVICE_ID:Number,
    latestVersion:Number,
    isBillingType :{
            type: Boolean,
            required: false
    },
    clientId :{
            type: Number,
            required: false
    },
    setupId:{
      type: Number,
      required: true 
    }
  },

  data() {
    return {
      activeSection: 'config',
      // isRuleServiceUpdateFormVisible: false,
      conditionId:0,
      nodeName:'',
      isChartHistory:true,
      rules: [],
      processedData:[],
      historyRules: [],
      historyProcessedData:[]
    };
  },
  created: async function () {
    this.bindNodeConfiguration();
    this.bindHistoryNodeConfig();
  },
    computed: {
    isLatestSelected() {
      return this.currentVersion === this.latestVersion;
    },
    currentLabel() {
      return this.isLatestSelected
        ? this.$t('CurrentVersion')
        : `Version Number : ${this.currentVersion}`;
    },
    previousLabel() {
      return this.previousVersion
        ? `Version Number : ${this.previousVersion}`
        : null;
    }
  },
  methods: {
    formatDate(date) {
      if (!date) return '--';
      return new Date(date).toLocaleDateString();
    },

    toggleSection(sectionName) {
      this.activeSection = this.activeSection === sectionName ? '' : sectionName;
    },
    //  showRuleServiceUpdateForm(CONFIGURATION_ID,BILLING_SERVICE_ID,SERVICE_ID,NODE_NAME) {
    //   this.selectedConfigurationId = CONFIGURATION_ID; 
    //   this.conditionId  = SERVICE_ID
    //   this.BILLING_SERVICE_ID=BILLING_SERVICE_ID;
    //   this.nodeName =NODE_NAME;
    //   this.isRuleServiceUpdateFormVisible = true; 
    // },
    addMoreRule: function () {
            var vm = this;
            vm.rules.push({
                ruleId: 0,
                ruleDisplayOrder: (vm.rules.length + 1),
                ruleName: "Rule " + (vm.rules.length + 1),
                version: (vm.rules.length + 1),
                ruleCondition: {},
                rules: [],
                parent: null,
                isDelete: false,
                isShowChild: true,
                hidebuttons: true,
                isUpdateRule: true
            })
    },
    
    bindNodeConfiguration :function(){
      var ths= this;
      let dt = this.nodeHistoryFullData.filter(item => item.DISPLAY_NODE_NAME !== 0 && item.DISPLAY_NODE_NAME !== "0" && item.DISPLAY_NODE_NAME !== null);
      // let dt = this.nodeHistoryFullData;
      let data = [];
      let globalCounter = 1;
      let rootItems = dt.filter(item => item.PARENT_MAPPING_ID === 0 || item.PARENT_MAPPING_ID === null);

      // Helper function to create the object
        function createRuleObject(item) {
            return {
                    ruleId: item.CLIENT_SERVICE_MAPPING_ID,
                    ruleDisplayOrder: item.DISPLAY_ORDER,
                    ruleName: item.DISPLAY_NODE_NAME.toUpperCase() === "GLOBAL~" ?  `Global ${globalCounter++}`  : "Rule " + item.DISPLAY_NODE_NAME,
                    version: item.DISPLAY_NODE_NAME,
                    ruleCondition: {
                                    conditionId: item.SERVICE_ID,
                                      serviceName: item.SERVICE_NAME,
                                      rateCode: "",
                                      isLeafChecked: item.IS_LEAF_NODE,
                                      condition: item.CONDITION,
                                      selectedFlag: {
                                          value: "grey",
                                          name: "grey"
                                      },
                                      nodeName: item.DISPLAY_NODE_NAME
                                  },
                      rules: [],
                      parent: null,
                      isDelete: false,
                      isShowChild: true
                  };
        }

      // Process root items
      rootItems.forEach(function (item) {
          let obj = createRuleObject(item);
          ths.processedData.push(item.CLIENT_SERVICE_MAPPING_ID);
          data.push(obj);
      });

                          // Process other items
      dt.forEach(function (item) {
          if (!ths.processedData.includes(item.CLIENT_SERVICE_MAPPING_ID)) {
              let obj = createRuleObject(item);
              let filteredData = dt.filter(itm => itm.PARENT_MAPPING_ID == item.CLIENT_SERVICE_MAPPING_ID);
              if (filteredData.length > 0) {
                  obj.rules = ths.getChildJson(filteredData, dt, item.CLIENT_SERVICE_MAPPING_ID, item.DISPLAY_NODE_NAME);
              }

              ths.processedData.push(item.CLIENT_SERVICE_MAPPING_ID);
                data.push(obj);
              }
      });
        ths.rules = data;
        if (ths.rules.length == 0) {
          ths.addMoreRule();
        }
    },
    bindHistoryNodeConfig(){
      var ths= this;
      let dt = this.nodeHistoryData.filter(item => item.DISPLAY_NODE_NAME !== 0 && item.DISPLAY_NODE_NAME !== "0" && item.DISPLAY_NODE_NAME !== null);
      // let dt = this.nodeHistoryFullData;
      let data = [];
      let globalCounter = 1;
      let rootItems = dt.filter(item => item.PARENT_MAPPING_ID === 0 || item.PARENT_MAPPING_ID === null);

      // Helper function to create the object
        function createRuleObject(item) {
            return {
                    ruleId: item.CLIENT_SERVICE_MAPPING_ID,
                    ruleDisplayOrder: item.DISPLAY_ORDER,
                    ruleName: item.DISPLAY_NODE_NAME.toUpperCase() === "GLOBAL~" ?  `Global ${globalCounter++}`  : "Rule " + item.DISPLAY_NODE_NAME,
                    version: item.DISPLAY_NODE_NAME,
                    ruleCondition: {
                                    conditionId: item.SERVICE_ID,
                                      serviceName: item.SERVICE_NAME,
                                      rateCode: "",
                                      isLeafChecked: item.IS_LEAF_NODE,
                                      condition: item.CONDITION,
                                      selectedFlag: {
                                          value: "grey",
                                          name: "grey"
                                      },
                                      nodeName: item.DISPLAY_NODE_NAME
                                  },
                      rules: [],
                      parent: null,
                      isDelete: false,
                      isShowChild: true
                  };
        }

      // Process root items
      rootItems.forEach(function (item) {
          let obj = createRuleObject(item);
          ths.historyProcessedData.push(item.CLIENT_SERVICE_MAPPING_ID);
          data.push(obj);
      });

                          // Process other items
      dt.forEach(function (item) {
          if (!ths.historyProcessedData.includes(item.CLIENT_SERVICE_MAPPING_ID)) {
              let obj = createRuleObject(item);
              let filteredData = dt.filter(itm => itm.PARENT_MAPPING_ID == item.CLIENT_SERVICE_MAPPING_ID);
              if (filteredData.length > 0) {
                  obj.rules = ths.getChildJson(filteredData, dt, item.CLIENT_SERVICE_MAPPING_ID, item.DISPLAY_NODE_NAME);
              }

              ths.historyProcessedData.push(item.CLIENT_SERVICE_MAPPING_ID);
                data.push(obj);
              }
      });
        ths.historyRules = data;
        if (ths.historyRules.length == 0) {
          ths.addMoreRule();
        }
    },
    getChildJson: function (filterData, dt, clientMappingId, parentNode) {
            let ths = this;
            let returnValue = []
            filterData.forEach(function (item, index) {
                var obj = {
                    ruleId: item.CLIENT_SERVICE_MAPPING_ID,
                    ruleDisplayOrder: item.DISPLAY_ORDER,
                    ruleName: "Rule " + item.DISPLAY_NODE_NAME,
                    version: item.DISPLAY_NODE_NAME,
                    ruleCondition: {
                        conditionId: item.SERVICE_ID,
                        serviceName: item.SERVICE_NAME,
                        rateCode: "",
                        isLeafChecked: item.IS_LEAF_NODE,
                        condition: item.CONDITION,
                        selectedFlag: {
                            value: "grey",
                            name: "grey"
                        },
                        nodeName: item.DISPLAY_NODE_NAME
                    },
                    rules: [],
                    parent: parentNode,
                    isDelete: false,
                    isShowChild: true
                }
                let filteredData = dt.filter((itm) => { return itm.PARENT_MAPPING_ID == item.CLIENT_SERVICE_MAPPING_ID });
                let child = [];
                if (filteredData.length > 0) {
                  
                    child = ths.getChildJson(filteredData, dt, item.CLIENT_SERVICE_MAPPING_ID, item.DISPLAY_NODE_NAME);
                }
                obj.rules = child;
                ths.processedData.push(item.CLIENT_SERVICE_MAPPING_ID);
                returnValue.push(obj);
            });
            return returnValue;
        }
  }
};
</script>

<style>
  .custom-accr .card-header em {
  font-size: 30px;
  margin-right: 5px;
}

