<template>
    <section>
        <loader :is-visible="isLoading"></loader>
        <tg-list :IsShowAction="true" :showCheckBox="true" ModuleName="BillingRule" :listType="['List']"
            :RenderRowActionMethod="renderActions" v-on:ActionButtonClick="actionButtonClick" SubModuleCode=""
            IdentityColumn="CONFIGURATION_ID" :HeaderText="$t('ManageBillingRule')" :ListData="BillingRuleData"
            :HeaderData="Headers" :callbackfunction="FetchData" :HeaderButtons="listheaderbuttons"
            :TotalRecords="TotalRecords" :SearchFields="leftSearchFields" :ListDataCallBackFunction="FetchData"
            :LegendArray="[]" :SortExp="sortExp" :SortBy="SortBy" :NorecordfoundText="$t('NoRecordfound')"
            v-on:LeftsearchButtonClick="leftCommonSearch" v-on:PagerButtonClick="pagerMethod"
            v-on:HeaderButtonClick="commonHeaderButtonClick" v-on:SortdataButtonClick="sortdata">
            <template v-slot:slotdata="{ data }" :routeInfo="$router">
                <!-- {{ data.row }} -->
                <template v-if="data.column.COLUMN_NAME == 'RULE_NAME'">
                    <a :href="OpenRuleDetail(data.row)"><i aria-hidden="true"></i>{{data.row.RULE_NAME }}
                    </a>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'CATEGORY_NAME'">
                    <span v-if="data.row.CATEGORY_NAME != null || data.row.CATEGORY_NAME != ''">
                        {{ data.row.CATEGORY_NAME }}
                    </span>
                    <span v-else>--</span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'CLIENT_NAME'">
                    <span v-if="data.row.CLIENT_NAME != null || data.row.CLIENT_NAME != ''">
                        {{ data.row.CLIENT_NAME }}
                    </span>
                    <span v-else>--</span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'UTILITYNAME'">
                    <span v-if="data.row.UTILITYNAME != null || data.row.UTILITYNAME != ''">
                        {{ data.row.UTILITYNAME }}
                    </span>
                    <span v-else>--</span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'STATENAME'">
                    <span v-if="data.row.STATENAME != null || data.row.STATENAME != ''">
                        {{ data.row.STATENAME }}
                    </span>
                    <span v-else>--</span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'EFFICATIVE_DATE_FROM'">
                    <td class="text-center single-action tourguide_a" v-if="data.row.EFFICATIVE_DATE_FROM">
                        {{ $d(data.row.EFFICATIVE_DATE_FROM) }}
                    </td>
                    <td class="text-center single-action tourguide_a" v-else>--</td>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'EFFICATIVE_DATE_TO'">
                    <td class="text-center single-action tourguide_a" v-if="data.row.EFFICATIVE_DATE_TO">
                        {{ $d(data.row.EFFICATIVE_DATE_TO) }}
                    </td>
                    <td class="text-center single-action tourguide_a" v-else>--</td>

                </template>
                <template v-if="data.column.COLUMN_NAME == 'CREATED_AT'">
                    <td class="text-center single-action tourguide_a" v-if="data.row.CREATED_AT">
                        {{ $d(data.row.CREATED_AT) }}
                    </td>
                    <td class="text-center single-action tourguide_a" v-else>--</td>

                </template>
                <template v-if="data.column.COLUMN_NAME == 'MODIFIED_AT'">
                    <td class="text-center single-action tourguide_a" v-if="data.row.MODIFIED_AT">
                        {{ $d(data.row.MODIFIED_AT) }}
                    </td>
                    <td class="text-center single-action tourguide_a" v-else>--</td>

                </template>
                <template v-if="data.column.COLUMN_NAME == 'MODIFIED_BY_NAME'">
                    <td class="text-center single-action tourguide_a"
                        v-if="data.row.MODIFIED_BY_NAME">
                        {{ data.row.MODIFIED_BY_NAME }}
                    </td>
                    <td class="text-center single-action tourguide_a" v-else>--</td>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'STATUS_ID'">
                    <div>
                        <listing-status :isfor="'Billing_Rule'" ref="updatestatus"
                            v-bind:dataid="data.row.CONFIGURATION_ID" data-controller="Billing_Rule"
                            v-bind:statuslist="StatusListForListing" v-bind:item="data.row.STATUS_ID"
                            data-action="index" v-bind:dataselected="data.row.STATUS_ID == 1001 ? 'Active' : 'Inactive'"
                            v-bind:callbackfunction="FetchData" v-bind:isselectedvaluestring="true" v-bind:title="data.row.STATUS_ID == 1001 ? 'Active' : 'Inactive'">
                        </listing-status>
                    </div>
                    <div>
                        <span v-bind:class="getStatusClassList(data.row.STATUS_ID, 'STATUS_ID')"
                            v-if="data.row.STATUS_ID == 'Active'">
                            {{ data.row.STATUS_ID }}
                        </span>
                        <span v-bind:class="getStatusClassList(data.row.STATUS_ID, 'STATUS_ID')"
                            v-if="data.row.STATUS_ID == 'Inactive'">
                            {{ data.row.STATUS_ID }}
                        </span>
                    </div>
                </template>
            </template>
        </tg-list>
        <!-- Clone Model  Start-->
        <div name="modal" v-if="isCloneModel">
             <div class="modal my-popups right fade d-block" :class="{ show: isShownClone }">
                <div role="document" class="modal-dialog" style="max-width: 1300px !important;">
                    <div class="modal-content">
                        <div
                            class="modal-header theme-primary partition-full d-flex justify-content-between align-items-center">
                            <h5 class="modal-title">
                                {{ $t('CloneRule') }}
                            </h5>
                            <button type="button" class="close" @click="CloseCloneModel">
                                <em class="fa fa-times" aria-hidden="true"></em>
                            </button>
                            <span class="user-guide">
                                <a class="ancuserguide text-white" data-toggle="collapse" href="javascript:;" role="button" aria-expanded="false" aria-controls="collapseExample">
                                    <em class="fa fa-files-o pr-2"></em>{{ $t('GuideForUser') }}
                                </a>
                                <div id="collapseReplyUG" class="divancuserguide collapse overflow-auto">
                                    <div id="scrollbarreplyuserguideMangeView" class="custom-scrollbar-js">
                                        <div class="con"  v-html="getUserGuideTitle()"></div>
                                    </div>
                                </div>
                            </span>
                        </div>

                        <div class="modal-body">
                            <dynamic-form lang="en" ref="validatePlan" :buttons="buttons" :schema="FormSchema"
                                :mandatorytext="$t('MandatoryString')">
                            </dynamic-form>
                        </div>
                    </div>
                </div>
            </div>
        </div>
        <!-- Clone Model End -->
        <BillingViewHistory v-if="isBillingHistoryPopup" :CONFIGURATION_ID="CONFIGURATION_ID" :BILLING_SERVICE_ID="BILLING_SERVICE_ID" :setupId="setupId" @close="isBillingHistoryPopup = false"></BillingViewHistory>
    </section>
</template>

<script>

import Schema from '../BillingRule/BillingRuleSchema';
import DataService from '../../services/DataService';
import BillingViewHistory from '../../components/Modals/BillingViewHistory.vue';


import moment from 'moment';
import {
    locateBillingService
} from "../../services/locateBillingService";
export default {
     components: {BillingViewHistory},
    data() {
        return {
            isLoading: false,
            BillingRuleData: [],
            isCloneModel: false,
            listActions: Schema.listActions,
            listheaderbuttons: Schema.buttons,
            cloneItem: [],
            StatusListForListing: [
                {
                    STATUS: "Active",
                    STATUS_ID: 1001,
                    STATUS_COLOR: "#ffffff",
                    STATUS_BG_COLOR: "#28a745",
                },
                {
                    STATUS: "Inactive",
                    STATUS_ID: 1002,
                    STATUS_COLOR: "#ffffff",
                    STATUS_BG_COLOR: "#d72435",
                },
            ],
            Headers: [
                {
                    "COLUMN_NAME": "RULE_NAME",
                    "DATA_TYPE": "text",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('BillingRuleName'),
                    "DISPLAY_ORDER": 1,
                },
                {
                    "COLUMN_NAME": "SERVICE_NAME",
                    "DATA_TYPE": "text",
                    "SORTABLE": true,
                    "VISIBLE": false,
                    "DISPLAY_NAME":  this.$t('ServiceName'),
                    "DISPLAY_ORDER": 2,
                },
                {
                    "COLUMN_NAME": "CLIENT_NAME",
                    "DATA_TYPE": "text",
                    "SORTABLE": true,
                    "VISIBLE": false,
                    "DISPLAY_NAME": 'Contract',
                    "DISPLAY_ORDER": 2,
                },
                {
                    "COLUMN_NAME": "UTILITYNAME",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": false,
                    "DISPLAY_NAME": this.$t('UtilityName'),
                    "DISPLAY_ORDER": 3,
                },
                {
                    "COLUMN_NAME": "CATEGORY_NAME",
                    "DATA_TYPE": "text",
                    "SORTABLE": true,
                    "VISIBLE": false,
                    "DISPLAY_NAME": 'Category',
                    "DISPLAY_ORDER": 4,
                },
                {
                    "COLUMN_NAME": "STATENAME",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": false,
                    "DISPLAY_NAME": this.$t('State'),
                    "DISPLAY_ORDER": 5,
                },
                {
                    "COLUMN_NAME": "EFFICATIVE_DATE_FROM",
                    "DATA_TYPE": "text",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('EffectiveFromDate'),
                    "DISPLAY_ORDER": 6,
                },
                {
                    "COLUMN_NAME": "EFFICATIVE_DATE_TO",
                    "DATA_TYPE": "text",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('EffectiveToDate'),
                    "DISPLAY_ORDER": 7,
                },
                {
                    "COLUMN_NAME": "STATUS_ID",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('Status'),
                    "DISPLAY_ORDER": 8,
                },
                {
                    "COLUMN_NAME": "CREATED_BY_NAME",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('CreatedBy'),
                    "DISPLAY_ORDER": 9,
                },
                {
                    "COLUMN_NAME": "CREATED_AT",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": false,
                    "DISPLAY_NAME": this.$t('CreatedAt'),
                    "DISPLAY_ORDER": 9,
                },
                {
                    "COLUMN_NAME": "MODIFIED_BY_NAME",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": false,
                    "DISPLAY_NAME": this.$t('ModifiedBy'),
                    "DISPLAY_ORDER": 9,
                },
                {
                    "COLUMN_NAME": "MODIFIED_AT",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": false,
                    "DISPLAY_NAME": this.$t('ModifiedAt'),
                    "DISPLAY_ORDER": 9,
                }

            ],
            FormSchema: [
                {
                    layoutType: "double",
                    Data: [
                        {
                            astype: "TextField",
                            label: this.$t('RuleName'),
                            name: 'RuleName',
                            palceholder: this.$t('RuleName'),
                            value: "",
                            validationRules: {
                                required: true
                            },
                            disabled: false,
                        },
                        {
                            astype: "SelectField",
                            label: this.$t('CompanyName'),
                            name: "CompanyName",
                            value: "",
                            placeholder: this.$t('Select'),
                            config: {
                                options: []
                            },
                            validationRules: {
                                required: true
                            },
                        },
                        {
                            astype: "DateField",
                            label: this.$t('EffectiveFromDate')+' '+'(M/D/YYYY)',
                            name: "Effectivefrom",
                            value: new Date().toLocaleDateString(),
                            placeholder: "",
                            config: {
                                format: "MM/DD/YYYY",
                                // minDate: new Date(),
                                // onChange: this.setTimerDate,
                                maxDate: false
                            },
                            validationRules: { "required": true },
                        },
                        {
                            astype: "DateField",
                            label: this.$t('EffectiveToDate')+' '+'(M/D/YYYY)',
                            name: "Effectiveto",
                            value: new Date('12/31/2099').toLocaleDateString(),
                            placeholder: "",
                            config: {
                                format: "MM/DD/YYYY",
                                minDate: new Date(),
                                onChange: this.setTimerDate,
                                maxDate: false
                            },
                            validationRules: { "required": true },
                        }, {
                            astype: "RadioField",
                            label: this.$t('IsRuleApllicableToAll'),
                            name: "allutilities",
                            value: "0",
                            config: {
                                options: [{ value: "1", name: "Yes" }, { value: "0", name: "No" }],
                                onChange: this.onChangeApplicable
                            },
                            validationRules: { "required": false, max: 100 },
                        },
                        {
                            astype: "SearchableSelectField",
                            label: this.$t('ClientID'),
                            name: "ContractName",
                            value: "",
                            placeholder: this.$t('SearchAndSelectContract'),
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                actionButtons: {
                                    selectAll: true,
                                    active: true,
                                    inactive: true,
                                    clear: true
                                },
                                isMultiple: false,
                                groupFields: ['groupText'],
                                minSearchLength: 0,
                                statusFieldConfig: {
                                    fieldName: 'status',
                                    activeValues: ['Active', 'active'],
                                    inactiveValues: ['Inactive', 'inactive'],
                                    activeColor: '#28a745',
                                    inactiveColor: '#dc3545'
                                },
                                onChange: this.onSelectionChange
                            },
                            validationRules: {
                                "required": true
                            },
                        },
                        {
                            astype: "SearchableSelectField",
                            label: this.$t('UtilityName'),
                            name: "UtilityName",
                            value: "",
                            placeholder: "Select Utility Name",
                            visibility: true,
                            isSearch: false,
                            config: {
                                options: [],
                                actionButtons: { selectAll: true,  clear: true },
                                groupFields: [],
                                isMultiple: true,
                                minSearchLength: 0,
                                statusFieldConfig: {
                                    fieldName: 'status',
                                    activeValues: ['Active', 'active'],
                                    inactiveValues: ['Inactive', 'inactive'],
                                    activeColor: '#28a745',
                                    inactiveColor: '#dc3545'
                                },
                            },
                            validationRules: {
                                "required": true
                            },
                        },

                    ],

                }
            ],
            buttons: [
                {
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>" + this.$t('Save'),
                    onClick: this.CreateClone
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>" + this.$t('Cancel'),
                    onClick: this.CloseCloneModel,
                },
            ],
            leftSearchFields: Schema.leftsearchSchema,
            searchByName: '',
            searchByClientName: '',
            utilities: '',
            searchByBiller: '',
            searchByState: [],
            SortBy: '',
            SortExp: '',
            noRecords: '',
            PageSize: "10",
            PageNumber: "1",
            TotalRecords: 0,
            CurrentPage: 1,
            TotalPages: 0,
            searchCondition: '',
            ListingData: [],
            servicePlanId: '',
            isBillingHistoryPopup:false,
            isBillingType:false,
            setupId:32,
            isShownClone:false,
            isSupervisor:false
        }
    },
    created: async function () {
        var vm = this;
        vm.UserType=vm.GetUserInfo.UserType;
        vm.CompanyId = this.GetUserInfo.CompanyId;
        vm.UserId = this.GetUserInfo.ID;
        this.isBillingType = localStorage.getItem('billingType') === 'USIC' ? true : false; 
        await vm.ManageLeftSearchFields();
        await vm.BindSupervisor();
        await vm.GetEmailConfigurationSetting();
        // await vm.CheckFeaturesForCompany('USICBILLING');
        await vm.FetchData();
        await vm.GetCompanylist();
        await vm.GetGroupList();
        
        await Schema.bindleftCommonSearchdropdown(vm,"STATE");
        await Schema.bindleftCommonSearchdropdown(vm,"UTILITIES");
        await Schema.bindleftCommonSearchdropdown(this,"BILLER"); 
    },
    methods: {
        getUserGuideTitle() {
            let text = this.$t('CloneBillingRule');
            return text
                // 🔥 IMPORTANT: escaped characters
                .replace(/\\n/g, '')
                .replace(/\\t/g, '&nbsp;');
        },
        ManageLeftSearchFields: async function(){
            const removeFields = (fields) => {
                this.leftSearchFields = this.leftSearchFields.filter(
                    ele => !fields.includes(ele.fieldName)
                );
            };
            if (this.isBillingType) {
                 removeFields(['ServiceName']);
            } else {
                removeFields(['CONTRACTNAME', 'UtilityName', 'STATE']);
            }
        },
        // CheckFeaturesForCompany: async function (type) {
        //     var vm = this;
        //     var appendingUrl = `featureCode=${type}`;
        //     await DataService.CheckExtraFeatures(appendingUrl).then(function (response) {
        //         if(type == 'USICBILLING'){
        //             if (response.data == true) {
        //                  vm.isBillingType = true;
        //             } 
        //         }
        //     });
        // },
        OpenRuleDetail: function (data) {
            var vm = this;
            if(this.isBillingType){
                return this.$router.resolve({
                        name: 'ViewConfiguration',
                        params: { id: data.CONFIGURATION_ID,serviceId:data.SERVICE_ID,mode :'View' }
                    }).href;

                // vm.$router.push({ name: 'ManageConfiguration', params: { id: data.CONFIGURATION_ID,serviceId:data.SERVICE_ID,mode :'View' } });
            }
            else{
                return this.$router.resolve({
                        name: 'ViewConfiguration',
                        params: {  id: data.CONFIGURATION_ID,serviceId:data.BILLING_SERVICE_ID,mode :'View' }
                    }).href;

                // vm.$router.push({ name: 'ManageConfiguration', params: { id: data.CONFIGURATION_ID,serviceId:data.BILLING_SERVICE_ID,mode :'View' } });
            }
          
            // if(this.isBillingType){
            //     vm.getNodeConfiguration(data.CONFIGURATION_ID,data.SERVICE_ID,'Edit')
            // }
            // else{
            //     vm.$router.push({ name: 'ManageConfiguration', params: { id: data.CONFIGURATION_ID,serviceId : data.BILLING_SERVICE_ID,mode :'Edit' } });
            // }
        },
        getNodeConfiguration: function (configId,serviceId,mode) {
            let ths = this;
            var prms = `configId=${configId}&serviceId=${serviceId}&isIncludeGlobalService=true&isView=${mode}`;
            DataService.GetNodeConfiguration(prms).then(function (res) {
                if (res?.data?.length > 0 && res.data[0]?.CONFIG_ID != null && res.data[0]?.SERVICE_ID != null) {
                    configId = res.data[0].CONFIG_ID;
                    serviceId = res.data[0].SERVICE_ID;
                    ths.$router.push({ name: 'ManageConfiguration', params: { id: configId, serviceId : serviceId,mode :'Edit' } });
                }
            });
        },
        BindSupervisor:  function () {
            var vm = this;           
            DataService.CheckIsSupervisor().then(response => {
                if (response.data) {                      
                    vm.isSupervisor=response.data;
                }
            });
        },

        GetEmailConfigurationSetting() {
            var vm = this;
            var params = `_CompanyId=${vm.CompanyId}&userId=${vm.UserId}&moduleName=User&configkey=CanViewAllContractData`;
            DataService.GetEmailConfigurationSetting(params)
                .then(response => {
                    if (response.data && response.data.length > 0)
                    {
                        if(response.data[0].CONFIG_DATA_VALUE.toLowerCase() === 'yes' || vm.UserType.toLowerCase()=='ca' || vm.isSupervisor){                           
                            Schema.bindleftCommonSearchdropdown(this,"BILLER");                      
                        } else {
                            vm.leftSearchFields = vm.leftSearchFields.filter((_, index) => index !== 4);
                        }
                    }
                })
                .catch(err => {
                    console.log(err);
                });
        },
        FetchData: async function () {
            var vm = this;
            const url = `searchByName=${vm.searchByName}&searchByClientName=${vm.searchByClientName}&utilities=${vm.utilities}&searchByState=${vm.searchByState}&searchByBiller=${vm.searchByBiller}&sortBy=${vm.SortBy}&sortExp=${vm.SortExp}&pageSize=${vm.PageSize}&pageNumber=${vm.PageNumber}&Plan_service_id=${vm.servicePlanId}`
            try {

                const response = await DataService.GetBillingRuleList(url);
                if (response.data && response.data.length > 0) {
                    vm.Headers.forEach((column) => {
                        column.settings = null;

                        if (["EFFICATIVE_DATE_FROM", "EFFICATIVE_DATE_TO", "STATUS_ID","RULE_NAME","CREATED_AT","MODIFIED_AT","MODIFIED_BY_NAME"].includes(column.COLUMN_NAME)) {
                            column.settings = { isInSlot: true };
                        }
                        if(this.isBillingType == true){
                            if (["CATEGORY_NAME","CLIENT_NAME","UTILITYNAME","STATENAME"].includes(column.COLUMN_NAME)) {
                                column.settings = { isInSlot: true };
                            }
                            if(column.COLUMN_NAME == "CATEGORY_NAME" || column.COLUMN_NAME == "CLIENT_NAME" || column.COLUMN_NAME == "UTILITYNAME" || column.COLUMN_NAME == "STATENAME"){
                                column.VISIBLE=true
                            }
                        }
                        else{
                            if(column.COLUMN_NAME == "SERVICE_NAME" || column.COLUMN_NAME == "CREATED_AT" || column.COLUMN_NAME == "MODIFIED_BY_NAME" || column.COLUMN_NAME == "MODIFIED_AT"){
                                column.VISIBLE=true;
                            }
                            
                        }
                    });
                    vm.BillingRuleData = response.data;
                    vm.BillingRuleData.forEach((element) => {
                        ['EFFICATIVE_DATE_FROM', 'EFFICATIVE_DATE_TO','CREATED_AT','MODIFIED_AT'].forEach((key) => {
                            if (element[key]) {
                                element[key] = new Date(element[key]);
                            }
                        });
                    });
                    vm.listheaderbuttons[2].isdisabled = true;
                    vm.TotalRecords = response.data[0].TOTAL_RECORDS;
                    vm.TotalPages = Math.ceil(vm.TotalRecords / vm.PageSize);
                    vm.CurrentPage = vm.PageNumber;
                    vm.noRecords = false;

                } else {
                    vm.BillingRuleData = [];
                    vm.TotalRecords = 0;
                    vm.noRecords = true;
                }

            } catch (error) {
                console.error("Error fetching data:", error);
            }
        },
        CreateClone: async function () {
            var vm = this;
            const isValid = await vm.$refs.validatePlan.validateForm.validate();
            if (!isValid) {
                this.isLoading = false;
                return;
            }
            var id = vm.cloneItem.CONFIGURATION_ID;
            var serviceId = this.isBillingType == true ? vm.cloneItem.SERVICE_ID: vm.cloneItem.BILLING_SERVICE_ID;
            var rulename = vm.$refs.validatePlan.getPropertyValue("RuleName", "value");
            var companyname = vm.$refs.validatePlan.getPropertyValue("CompanyName", "value");
            var effectivefrom = vm.$refs.validatePlan.getPropertyValue("Effectivefrom", "value");
            var effectiveto = vm.$refs.validatePlan.getPropertyValue("Effectiveto", "value");
            var contractname = vm.$refs.validatePlan.getPropertyValue("ContractName", "value");
            var isruleapplication = vm.$refs.validatePlan.getPropertyValue("allutilities", "value");
            var utilityValues = vm.$refs.validatePlan.getPropertyValue("UtilityName", "value");
            var selectUtility = Array.isArray(utilityValues) ? utilityValues.join(",") : utilityValues;
            const obj = {
                Id: id,
                ServiceId: serviceId,
                Client_Id: contractname,
                RuleName: rulename,
                CompanyName: companyname,
                EffectiveFrom: effectivefrom,
                EffectiveTo: effectiveto,
                ContractName: contractname,
                isRuleApplication: isruleapplication,
                SelectedUtility: selectUtility,
            }
            var jsonData = JSON.stringify(obj);
            await DataService.CreateRuleClone(jsonData).then((response) => {
                if (response.data != '') {
                    if (Number(response.data.status) == 0) {
                        this.ShowAlert(this.$t('AddedSuccess', [this.$t('Clone')]), "Success", true, this.$t('Alert'));
                        vm.FetchData();
                        vm.cloneItem = [];
                        vm.CloseCloneModel();
                    }else if(Number(response.data.status) == 1 ){
                          vm.ShowAlert(vm.$t("RuleNameAlreadyExists"), "warning", true);
                    }else if(Number(response.data.status) == -11 ){
                          vm.ShowAlert(vm.$t("RuleNameAlreadyExistsForClient"), "warning", true);
                    }else if(Number(response.data.status) == -22 ){
