        ConvertJSONToCSV: function (jsonData, filename, showHeader) {
            const jsonString = JSON.stringify(jsonData);
            const data = JSON.parse(jsonString);
            var excludeColumns=[];
            var headerMap ={};
            if(this.isBillingType == true){
                excludeColumns = ['CONFIGURATION_ID','SERVICE_ID','CONDITION', 'INVOICE_TEMPLATE', 'DURATION', 'AUTO_INVOICE', 'BILLING_SERVICE_ID','MODIFIED_BY_NAME','CREATED_AT',
                'INVOICE_TEMPLATE_NAME','MODIFIED_AT','Utility Name','SERVICE_NAME','STATUS_ID','TEMPORARY_CLONED_FROM','COMPANY_ID','SETUP_ID','ROWNUMBERS','TOTAL_RECORDS','ROWNUMBER'];
           
                headerMap = {
                    'RULE NAME': 'Rule Name', 'CLIENT NAME': 'Client Name', 'UTILITY NAME': 'Utility Name','COMPANYNAME':'Company Name', 'CATEGORY_NAME': 'Category Name', 'STATE':'State Name','CHARGE_TYPE':'Charge Type','STATUS':'Status',
                    'EFFECTIVE_DATE_FROM': 'Effective Date From','EFFECTIVE_DATE_TO':'Effective Date To','CREATED_BY_NAME' :'Created By Name'
                   
                };
            }
            else
            {
                excludeColumns = ['CONFIGURATION_ID', 'INVOICE_TEMPLATE','CONDITION', 'DURATION', 'AUTO_INVOICE', 'BILLING_SERVICE_ID', 'CLIENT_NAME','CHARGE_TYPE',
                'INVOICE_TEMPLATE_NAME','Utility Name','COMPANYNAME','STATUS_ID','STATENAME','TEMPORARY_CLONED_FROM','SETUP_ID','CATEGORY_NAME','ROWNUMBERS','TOTAL_RECORDS','UTILITYNAME'];
           
                headerMap = {
                    'ROWNUMBER': 'Sr No',
                    'RULE_NAME': 'Rule Name', 'SERVICE_NAME': 'Service Name', 'CLIENT_NAME': 'Client Name', 'UTILITYNAME': 'Utility Name', 'CATEGORY_NAME': 'Category Name', 'STATENAME':'State Name','STATUS_NAME':'Status Name',
                    'EFFICATIVE_DATE_FROM': 'Effective From','EFFICATIVE_DATE_TO':'Effective To','CREATED_BY_NAME' :'Created By','CREATED_AT':'Created At','MODIFIED_BY_NAME':'Modified By',
                    'MODIFIED_AT':'Modified At'
                };
            }
            
            if (!Array.isArray(data) || data.length === 0) {
                console.warn("No valid data to convert.");
                return;
            }
            if (data.length > 0) {
                const headers = Object.keys(data[0]);
                const filteredHeaders = headers.filter(header => !excludeColumns.includes(header));
                const mappedHeaders = filteredHeaders.map(header => headerMap[header] || header);
                const rows = data.map(row => {
                    return mappedHeaders.map(mappedHeader => {
                        const originalHeader = filteredHeaders[mappedHeaders.indexOf(mappedHeader)];
                        let cellValue = row[originalHeader] !== undefined && row[originalHeader] !== null ? String(row[originalHeader]) : '';
                        if (cellValue.includes(',') || cellValue.includes('\n') || cellValue.includes('"')) {
                            cellValue = `"${cellValue.replace(/"/g, '""')}"`;
                        }

                        return cellValue;
                    }).join(',');
                });
                const csvContent = (showHeader ? [mappedHeaders.join(',')] : []).concat(rows).join('\n');
                const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
                const link = document.createElement('a');
                link.setAttribute('href', URL.createObjectURL(blob));
                link.setAttribute('download', `${filename}.csv`);
                link.click();
            } else {
                console.log("No valid data to convert.");
            }
        },
